import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { DefaultMainStageHeader } from "../../utils";
import { stockStrings } from '../config';
import { stockActions } from '../actions';


const style = theme => ({
    root: {
    }
})
class _TransfersStageHeader extends Component {
    cancelEditHandler = () => {        
        stockActions.setStockTransferEditMode(false)(this.props.dispatch);
    }
    editBtnHandler = ( ) => {
        const {
            dispatch,
            [stockStrings.stockTransferEditMode] : stockTransferEditMode
        } = this.props;
        if(stockTransferEditMode){
            //do something
        }
        stockActions.setStockTransferEditMode(!Boolean(stockTransferEditMode))(dispatch);
    }
    render() {
        const {
            classes,
            [stockStrings.stockTransferEditMode] : stockTransferEditMode
        } = this.props;
        return (
            <DefaultMainStageHeader
                cancelEditHandler={this.cancelEditHandler.bind(this)}
                editBtnHandler={this.editBtnHandler.bind(this)}
                editMode={stockTransferEditMode}
                />
        );
    }
}


_TransfersStageHeader.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.stockTransferEditMode] : stockReducer[stockStrings.stockTransferEditMode],
})


export const TransfersStageHeader = connect(mapStateToProps)(withStyles(style)(_TransfersStageHeader));
export {TransfersStageHeader as default}