import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { stockStrings } from '../config';
import { stockActions } from '../actions';
import { headerActions, headerStrings, breadCrumbActions, 
    mainStageHeaderAction, mainStageHeaderStrings, MyTable, 
    EditableCellMapFormat, MyListCardMenuPopup, MyDialog } from "../../utils";
import { routeNamesInventory } from '../../routeNames';
import TransfersStageHeader from './TransfersStageHeader'
import { TextField, Chip, Button } from '@material-ui/core';
import {ItemSelection} from '../../INVProducts/ItemSelection';


const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _Transfers extends Component {
    constructor(props) {
        super(props);
        this.state = {
            transfers : null,
            transfersUnusable : null,
            dialogOpenStatus : true
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "TRANSFERS",
            [headerStrings.backButtonAction] : {}
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Stock Transfers", path : routeNamesInventory.stockTransfers},
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                TransfersStageHeader
            ]
        })(dispatch);
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch,
            [stockStrings.stores] : stores,
            [stockStrings.itemPackages] : itemPackages
        } = this.props;
        stockActions.getAllTransfers()(dispatch);
        if(!stores) stockActions.getStores()(dispatch);
        if(!itemPackages)stockActions.getItemPackages()(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {[stockStrings.stockTransfers] : transfers} = props;
        if(!state.transfersUnusable && transfers){
            state.transfers = state.transfersUnusable = transfers;
        }else if(JSON.stringify(state.transfersUnusable) !==
        JSON.stringify(transfers)){
            state.transfers = state.transfersUnusable = transfers;
        }
        return state;
    }
    cellMapFormat = superProps => props=><EditableCellMapFormat {...props} {...superProps}/>
    listItemClick = cellMap => (item, index) => {
        console.log(cellMap, item, index);
    }
    dialogDisplayHandler = dialogOpenStatus => ()=>this.setState({dialogOpenStatus})
    tableCellContentView = (stores, packages) => (editing, {row, cellMap}) => {
        let list = stores;
        if(editing){
            switch(cellMap){
                case "items" : return <Button onClick={this.dialogDisplayHandler(true)} variant="outlined" color="secondary">items</Button>;
                case "packageId" : list = packages;
                case "toStoreId" : 
                case "fromStoreId" : 
                    return <MyListCardMenuPopup
                                myListCardProps={{
                                    list,
                                    itemNameProp : "name",
                                    listItemClick : this.listItemClick(cellMap),
                                }}/>
                case "count" : return <TextField type="number"/>;
                default : return <TextField/>
            }
        }else{
            switch(cellMap){
                case "items" :
                    return row[cellMap] && row[cellMap].map((item, index)=>{
                        return <Chip label={item} key={index} size="small"/>
                    });
                case "toStoreId" : 
                case "fromStoreId" : 
                    if(!stores) return null;
                    const {item} = stores.getFirstObjectByPropValue("_id", row[cellMap]) || {};
                    return item ? item.name : null;
                case "packageId" : 
                    if(!packages) return null;
                    const {item : packageItem} = packages.getFirstObjectByPropValue("_id", row[cellMap]) || {};
                    return packageItem ? packageItem.name : null;
                default : return row[cellMap];
            }
        }
    }
    continueFromDialog = data => {
        console.log(data);
        this.dialogDisplayHandler(false)();
    }
    render() {
        const {
            classes,
            [stockStrings.stockTransferEditMode] : editMode,
            [stockStrings.stores] : stores,
            [stockStrings.itemPackages] : packages,
        } = this.props;
        let {transfers, dialogOpenStatus} = this.state;
        let header = ["ID", "Date", "Items", "Store (From)", "Store (To)", "Package(s)", "Count"];
        let dataMap =  ["_id", "date", "items", "fromStoreId", "toStoreId", "packageId", "count"];
        if(editMode){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            transfers = transfers ? 
                [...transfers.map(item=>({...item, editable : true, delible: true})), {new : true}] :
                [{new : true}];
        }
        return (
            <div className={classes.root}>
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={transfers}
                    CellMap={this.cellMapFormat({
                        skipEdit : ["_id", "date"],
                        tableCellContentView : this.tableCellContentView(
                                stores, packages
                            ),
                    })}
                    />
                <MyDialog open={dialogOpenStatus}>
                    <ItemSelection 
                        closeDialog={this.dialogDisplayHandler(false)}
                        continueAction={this.continueFromDialog.bind(this)}/>
                </MyDialog>
            </div>
        );
    }
}


_Transfers.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.stockTransfers] : stockReducer[stockStrings.stockTransfers],
    [stockStrings.stockTransferEditMode] : stockReducer[stockStrings.stockTransferEditMode],
    [stockStrings.itemPackages] : stockReducer[stockStrings.itemPackages],
    [stockStrings.stores] : stockReducer[stockStrings.stores],
})


export const Transfers = connect(mapStateToProps)(withStyles(style)(_Transfers));
export {Transfers as default}